import{_ as a,c as s,o as l,a5 as n}from"./chunks/framework.DwbewbAn.js";const _=JSON.parse('{"title":"日志","description":null,"frontmatter":{"lang":"zh-CN","title":"日志","description":null},"headers":[],"relativePath":"doc/数据库/Mysql/基础/日志/Relay log/relay log.md","filePath":"packages/doc/src/数据库/Mysql/基础/日志/Relay log/relay log.md","lastUpdated":1711354439000}'),e={name:"doc/数据库/Mysql/基础/日志/Relay log/relay log.md"},r=n(`<h1 id="relay-log" tabindex="-1">Relay log <a class="header-anchor" href="#relay-log" aria-label="Permalink to &quot;Relay log&quot;">​</a></h1><p>官方链接：<a href="https://dev.mysql.com/doc/refman/5.7/en/replica-logs-relaylog.html" target="_blank" rel="noreferrer">https://dev.mysql.com/doc/refman/5.7/en/replica-logs-relaylog.html</a></p><h2 id="_1-作用" tabindex="-1">1.作用 <a class="header-anchor" href="#_1-作用" aria-label="Permalink to &quot;1.作用&quot;">​</a></h2><p>Relay log，我们翻译成中文，一般叫做中继日志，一般情况下它在MySQL主从同步读写分离集群的从节点才开启。主节点一般不需要这个日志。 “中继日志”统称为一组编号的中继日志文件加上索引文件，可以通过<a href="https://dev.mysql.com/doc/refman/5.7/en/mysqlbinlog.html" target="_blank" rel="noreferrer"><strong>mysqlbinlog</strong></a>读取。</p><p>文件组成与binlog一致，索引文件+数据文件</p><p>![在这里插入图片描述](relay log.images/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L2phdmFhbmRkb25ldA==,size_16,color_FFFFFF,t_70.png)</p><h2 id="_2-如何开启" tabindex="-1">2.如何开启 <a class="header-anchor" href="#_2-如何开启" aria-label="Permalink to &quot;2.如何开启&quot;">​</a></h2><p>开启relaylog可以通过参数<code>relay_log</code>来配置。在<code>my.cnf</code>配置文件中，增加如下配置就可以开启relaylog。</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>[mysqld]</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 启用中继日志，其中mysql-relay表示日志的文件名称，文件存放在datadir参数指向的目录下面。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>relay-log=mysql-relay</span></span>
<span class="line"><span></span></span>
<span class="line"><span># relaylog的其他选项配置</span></span>
<span class="line"><span></span></span>
<span class="line"><span>relay_log_info_repository=table</span></span>
<span class="line"><span>relay_log_recovery=on</span></span>
<span class="line"><span>sync_relay_log=1</span></span>
<span class="line"><span>sync_relay_log_info=1</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><p>验证relay log开启的效果 如果没有开启relaylog，那么参数relay_log后面是没有任何值的。如果开启了relaylog，那么参数relay_log后面会有对一个的relaylog日志文件的名称，又称之为basename，后缀使用序列号标识。</p><p>下面是一个没有开启relaylog和一个开启了relaylog的对比结果，</p><p>开启relaylog后，我们在从节点服务器上的可以查看到具体的relaylog日志文件，其中的index文件是一个索引文件，和binlog中的索引文件一样。如下所示： ![在这里插入图片描述](relay log.images/watermark,type_ZmFuZ3poZW5naGVpdGk,shadow_10,text_aHR0cHM6Ly9ibG9nLmNzZG4ubmV0L2phdmFhbmRkb25ldA==,size_16,color_FFFFFF,t_70-20211124014416213.png)</p><p>配置之后，重启MySQL数据库实例，这样就会在datadir参数所指向的目录下面(如果不修改参数datadir的值，默认为/var/lib/mysql这个目录)生成mysql-relay.00000X的relay日志文件，文件的后缀名称表示日志生成的顺序，从1开始累加。</p><p>如果想自定义日志的路径，可以在这里指定文件的具体路径。例如配置为：relay-log=/data/log/relaylog/myrelay，则会在/data/log/relaylog目录下面，生成myrelay.000001这样的relaylog日志文件。 开启relaylog后，我们在从节点服务器上的可以查看到具体的relaylog日志文件，其中的index文件是一个索引文件，和binlog中的索引文件一样。如下所示：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>root@slave3:/var/lib/mysql# pwd</span></span>
<span class="line"><span>/var/lib/mysql</span></span>
<span class="line"><span>root@slave3:/var/lib/mysql# ls -lstr mysql-relay*</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql 203 Jan  3 11:20 mysql-relay.000026</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql 203 Jan  3 11:20 mysql-relay.000027</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql 154 Jan  3 11:20 mysql-relay.000028</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql  63 Jan  3 11:20 mysql-relay.index</span></span>
<span class="line"><span>root@slave3:/var/lib/mysql# cat mysql-relay.index</span></span>
<span class="line"><span>./mysql-relay.000026</span></span>
<span class="line"><span>./mysql-relay.000027</span></span>
<span class="line"><span>./mysql-relay.000028</span></span>
<span class="line"><span>root@slave3:/var/lib/mysql#</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h2 id="_3-relay-log日志相关参数" tabindex="-1">3.relay log日志相关参数 <a class="header-anchor" href="#_3-relay-log日志相关参数" aria-label="Permalink to &quot;3.relay log日志相关参数&quot;">​</a></h2><h4 id="max-relay-log-size-relaylog日志文件的最大值-默认为0-表示和binlog日志文件大小一样。如果不为0-表示relaylog日志文件的最大值就是设置的对应的大小-该参数的单位为byte。" tabindex="-1">max_relay_log_size：relaylog日志文件的最大值，默认为0，表示和binlog日志文件大小一样。如果不为0，表示relaylog日志文件的最大值就是设置的对应的大小，该参数的单位为byte。 <a class="header-anchor" href="#max-relay-log-size-relaylog日志文件的最大值-默认为0-表示和binlog日志文件大小一样。如果不为0-表示relaylog日志文件的最大值就是设置的对应的大小-该参数的单位为byte。" aria-label="Permalink to &quot;max_relay_log_size：relaylog日志文件的最大值，默认为0，表示和binlog日志文件大小一样。如果不为0，表示relaylog日志文件的最大值就是设置的对应的大小，该参数的单位为byte。&quot;">​</a></h4><h4 id="relay-log-设置的relaylog的日志文件路径和名称。如果不设置路径-只是设置文件名-则路径是在datadir参数所指向的磁盘目录。如果设置了目录-则会把relaylog写在对应的目录下。如果设置了目录-则要注意这个目录需要让mysql有对应的读写的权限才可以-否则启动mysql数据库会失败。" tabindex="-1">relay_log：设置的relaylog的日志文件路径和名称。如果不设置路径，只是设置文件名，则路径是在datadir参数所指向的磁盘目录。如果设置了目录，则会把relaylog写在对应的目录下。如果设置了目录，则要注意这个目录需要让MySQL有对应的读写的权限才可以，否则启动MySQL数据库会失败。 <a class="header-anchor" href="#relay-log-设置的relaylog的日志文件路径和名称。如果不设置路径-只是设置文件名-则路径是在datadir参数所指向的磁盘目录。如果设置了目录-则会把relaylog写在对应的目录下。如果设置了目录-则要注意这个目录需要让mysql有对应的读写的权限才可以-否则启动mysql数据库会失败。" aria-label="Permalink to &quot;relay_log：设置的relaylog的日志文件路径和名称。如果不设置路径，只是设置文件名，则路径是在datadir参数所指向的磁盘目录。如果设置了目录，则会把relaylog写在对应的目录下。如果设置了目录，则要注意这个目录需要让MySQL有对应的读写的权限才可以，否则启动MySQL数据库会失败。&quot;">​</a></h4><h4 id="relay-log-basename-relaylog日志文件的基础名称-就是去掉文件后缀之后的文件名称。" tabindex="-1">relay_log_basename：relaylog日志文件的基础名称，就是去掉文件后缀之后的文件名称。 <a class="header-anchor" href="#relay-log-basename-relaylog日志文件的基础名称-就是去掉文件后缀之后的文件名称。" aria-label="Permalink to &quot;relay_log_basename：relaylog日志文件的基础名称，就是去掉文件后缀之后的文件名称。&quot;">​</a></h4><h4 id="relay-log-index-relaylog日志的索引文件-里面记录了所有当前有效的relaylog日志文件列表。可以指定这个索引文件的名称和存储目录-不过我们一般配置它和relaylog在同一目录下。" tabindex="-1">relay_log_index：relaylog日志的索引文件，里面记录了所有当前有效的relaylog日志文件列表。可以指定这个索引文件的名称和存储目录，不过我们一般配置它和relaylog在同一目录下。 <a class="header-anchor" href="#relay-log-index-relaylog日志的索引文件-里面记录了所有当前有效的relaylog日志文件列表。可以指定这个索引文件的名称和存储目录-不过我们一般配置它和relaylog在同一目录下。" aria-label="Permalink to &quot;relay_log_index：relaylog日志的索引文件，里面记录了所有当前有效的relaylog日志文件列表。可以指定这个索引文件的名称和存储目录，不过我们一般配置它和relaylog在同一目录下。&quot;">​</a></h4><h4 id="relay-log-info-file-这个文件里面-记录当前正在使用到的relaylog的文件名称和日志文件中的位置偏移量-以及master节点上面的binlog日志偏移量。这个文件的名称为relay-log-info-它的目录和relaylog在同级目录下。" tabindex="-1">relay_log_info_file：这个文件里面，记录当前正在使用到的relaylog的文件名称和日志文件中的位置偏移量，以及master节点上面的binlog日志偏移量。这个文件的名称为relay-log.info，它的目录和relaylog在同级目录下。 <a class="header-anchor" href="#relay-log-info-file-这个文件里面-记录当前正在使用到的relaylog的文件名称和日志文件中的位置偏移量-以及master节点上面的binlog日志偏移量。这个文件的名称为relay-log-info-它的目录和relaylog在同级目录下。" aria-label="Permalink to &quot;relay_log_info_file：这个文件里面，记录当前正在使用到的relaylog的文件名称和日志文件中的位置偏移量，以及master节点上面的binlog日志偏移量。这个文件的名称为relay-log.info，它的目录和relaylog在同级目录下。&quot;">​</a></h4><h4 id="relay-log-info-repository-这个参数标识着上面的relay-log-info-file中的信息是记录在磁盘目录上-还是记录在表中。它有两个取值范围-分别是file或者table。" tabindex="-1">relay_log_info_repository：这个参数标识着上面的relay_log_info_file中的信息是记录在磁盘目录上，还是记录在表中。它有两个取值范围，分别是FILE或者TABLE。 <a class="header-anchor" href="#relay-log-info-repository-这个参数标识着上面的relay-log-info-file中的信息是记录在磁盘目录上-还是记录在表中。它有两个取值范围-分别是file或者table。" aria-label="Permalink to &quot;relay_log_info_repository：这个参数标识着上面的relay_log_info_file中的信息是记录在磁盘目录上，还是记录在表中。它有两个取值范围，分别是FILE或者TABLE。&quot;">​</a></h4><p>如果relay_log_info_repository=FILE，会在relaylog同级的磁盘目录下，生成relay-log.info文件，用于记录当前relaylog的日志偏移量和master节点上面的binlog日志偏移量。如下是配置为FILE的时候，relay-log.info日志文件的位置信息和内容信息：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>root@slave3:/var/lib/mysql# pwd</span></span>
<span class="line"><span>/var/lib/mysql</span></span>
<span class="line"><span>root@slave3:/var/lib/mysql# ls -lstr *relay*</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql 343 Jan  4 17:40 mysql-relay.000038</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql 203 Jan  4 17:40 mysql-relay.000039</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql 320 Jan  4 17:40 mysql-relay.000040</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql  84 Jan  4 17:40 worker-relay-log.info.1</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql  84 Jan  4 17:40 worker-relay-log.info.2</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql  84 Jan  4 17:40 worker-relay-log.info.3</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql  84 Jan  4 17:40 worker-relay-log.info.4</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql  84 Jan  4 17:40 worker-relay-log.info.5</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql  84 Jan  4 17:40 worker-relay-log.info.6</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql  63 Jan  4 17:40 mysql-relay.index</span></span>
<span class="line"><span>4 -rw-r----- 1 mysql mysql  55 Jan  4 17:40 relay-log.info</span></span>
<span class="line"><span>root@slave3:/var/lib/mysql# more relay-log.info</span></span>
<span class="line"><span>7</span></span>
<span class="line"><span>./mysql-relay.000038</span></span>
<span class="line"><span>320</span></span>
<span class="line"><span>mysql-bin.000008</span></span>
<span class="line"><span>315</span></span>
<span class="line"><span>0</span></span>
<span class="line"><span>0</span></span>
<span class="line"><span>1</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 当使用逻辑时钟的方式来优化从节点执行relaylog日志速度的时候，会有多个这样的.info文件生成。</span></span>
<span class="line"><span></span></span>
<span class="line"><span># 逻辑时钟配置为几个，这里就有几个对应的.info文件，后面跟着数字来区分。</span></span>
<span class="line"><span></span></span>
<span class="line"><span>root@slave3:/var/lib/mysql# more worker-relay-log.info.3</span></span>
<span class="line"><span>3</span></span>
<span class="line"><span></span></span>
<span class="line"><span>0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>0</span></span>
<span class="line"><span></span></span>
<span class="line"><span>0</span></span>
<span class="line"><span>0</span></span>
<span class="line"><span>64</span></span>
<span class="line"><span></span></span>
<span class="line"><span>root@slave3:/var/lib/mysql#</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br><span class="line-number">15</span><br><span class="line-number">16</span><br><span class="line-number">17</span><br><span class="line-number">18</span><br><span class="line-number">19</span><br><span class="line-number">20</span><br><span class="line-number">21</span><br><span class="line-number">22</span><br><span class="line-number">23</span><br><span class="line-number">24</span><br><span class="line-number">25</span><br><span class="line-number">26</span><br><span class="line-number">27</span><br><span class="line-number">28</span><br><span class="line-number">29</span><br><span class="line-number">30</span><br><span class="line-number">31</span><br><span class="line-number">32</span><br><span class="line-number">33</span><br><span class="line-number">34</span><br><span class="line-number">35</span><br><span class="line-number">36</span><br><span class="line-number">37</span><br><span class="line-number">38</span><br><span class="line-number">39</span><br><span class="line-number">40</span><br><span class="line-number">41</span><br><span class="line-number">42</span><br></div></div><p>当把relay_log_info_repository的值改为TABLE之后，上面列出来的关于ls -lstr <em>relay</em>info*输出的.info结尾的文件都会自动消失不见。</p><p>这里需要注意一个问题：如果想把relay_log_info_repository原先配置的TABLE，想改为FILE，或者原先是FILE,想改为TABLE。除了把my.cnf配置文件中参数relay_log_info_repository值改为想设置的值之外，还需要登录到MySQL的从节点命令行中，使用stop slave的命令停止从节点同步任务，然后再执行set global relay_log_info_repository=xxxx的命令，然后再使用start slave命令启动从节点同步任务，这样才可以切换成功。否则可能会有如下的错误提示：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>2021-01-04T09:34:56.967913Z 0 [Warning] It is not possible to change the type of the relay log repository because there are workers repositories with possible execution gaps. The value of --relay_log_info_repository is altered to one of the found Worker repositories. The gaps have to be sorted out before resuming with the type change.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>mysql&gt; set GLOBAL  relay_log_info_repository=&#39;file&#39;;</span></span>
<span class="line"><span>ERROR 3081 (HY000): This operation cannot be performed with running replication threads; run STOP SLAVE FOR CHANNEL &#39;&#39; first</span></span>
<span class="line"><span>mysql&gt; set GLOBAL  relay_log_info_repository=&#39;table&#39;;</span></span>
<span class="line"><span>ERROR 3081 (HY000): This operation cannot be performed with running replication threads; run STOP SLAVE FOR CHANNEL &#39;&#39; first</span></span>
<span class="line"><span>mysql&gt;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><p>如果relay_log_info_repository=TABLE，则不会生成relay-log.info文件，信息会记录在mysql.slave_relay_log_info的表中，推荐使用这种方式，方便查看主节点和从节点的日志偏移量信息。如下所示：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code"><code><span class="line"><span>mysql&gt; select * from mysql.slave_relay_log_info\\G</span></span>
<span class="line"><span>*************************** 1. row ***************************</span></span>
<span class="line"><span>  Number_of_lines: 7</span></span>
<span class="line"><span>   Relay_log_name: ./mysql-relay.000026</span></span>
<span class="line"><span>    Relay_log_pos: 4</span></span>
<span class="line"><span>  Master_log_name: mysql-bin.000007</span></span>
<span class="line"><span>   Master_log_pos: 2235</span></span>
<span class="line"><span>        Sql_delay: 0</span></span>
<span class="line"><span>Number_of_workers: 6</span></span>
<span class="line"><span>               Id: 1</span></span>
<span class="line"><span>     Channel_name:</span></span>
<span class="line"><span>1 row in set (0.01 sec)</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br></div></div><h4 id="relay-log-purge-开启或关闭在不需要的时候自动删除中转日志-默认开启。这是个全局变量-可以通过set-global-relay-log-purge-0-进行动态的设置。" tabindex="-1">relay_log_purge：开启或关闭在不需要的时候自动删除中转日志，默认开启。这是个全局变量，可以通过SET GLOBAL relay_log_purge=0 进行动态的设置。 <a class="header-anchor" href="#relay-log-purge-开启或关闭在不需要的时候自动删除中转日志-默认开启。这是个全局变量-可以通过set-global-relay-log-purge-0-进行动态的设置。" aria-label="Permalink to &quot;relay_log_purge：开启或关闭在不需要的时候自动删除中转日志，默认开启。这是个全局变量，可以通过SET GLOBAL relay_log_purge=0 进行动态的设置。&quot;">​</a></h4><h4 id="relay-log-recovery-假如slave从库宕机后-很有可能导致relay-log日志文件损坏-导致一部分中继日志没有处理。如果参数设置为开启on的状态-则自动放弃所有未执行的relay-log-并且重新从master上获取对应的日志-这样就保证了relay-log的完整性。默认情况下该功能是关闭的-将relay-log-recovery的值设置为on时-可在slave从库上开启这个功能-建议将relay-log-recovery设置为on。" tabindex="-1">relay_log_recovery：假如slave从库宕机后，很有可能导致relay log日志文件损坏，导致一部分中继日志没有处理。如果参数设置为开启ON的状态，则自动放弃所有未执行的relay log，并且重新从master上获取对应的日志，这样就保证了relay-log的完整性。默认情况下该功能是关闭的，将relay_log_recovery的值设置为ON时，可在slave从库上开启这个功能，建议将relay_log_recovery设置为ON。 <a class="header-anchor" href="#relay-log-recovery-假如slave从库宕机后-很有可能导致relay-log日志文件损坏-导致一部分中继日志没有处理。如果参数设置为开启on的状态-则自动放弃所有未执行的relay-log-并且重新从master上获取对应的日志-这样就保证了relay-log的完整性。默认情况下该功能是关闭的-将relay-log-recovery的值设置为on时-可在slave从库上开启这个功能-建议将relay-log-recovery设置为on。" aria-label="Permalink to &quot;relay_log_recovery：假如slave从库宕机后，很有可能导致relay log日志文件损坏，导致一部分中继日志没有处理。如果参数设置为开启ON的状态，则自动放弃所有未执行的relay log，并且重新从master上获取对应的日志，这样就保证了relay-log的完整性。默认情况下该功能是关闭的，将relay_log_recovery的值设置为ON时，可在slave从库上开启这个功能，建议将relay_log_recovery设置为ON。&quot;">​</a></h4><h4 id="relay-log-space-limit-防止中继日志写满磁盘-这里设置中继日志最大限额。但此设置存在主库崩溃-从库中继日志不全的情况-不到万不得已-不推荐使用。设置为0表示不启用该功能。该参数的默认值就是0。" tabindex="-1">relay_log_space_limit：防止中继日志写满磁盘，这里设置中继日志最大限额。但此设置存在主库崩溃，从库中继日志不全的情况，不到万不得已，不推荐使用。设置为0表示不启用该功能。该参数的默认值就是0。 <a class="header-anchor" href="#relay-log-space-limit-防止中继日志写满磁盘-这里设置中继日志最大限额。但此设置存在主库崩溃-从库中继日志不全的情况-不到万不得已-不推荐使用。设置为0表示不启用该功能。该参数的默认值就是0。" aria-label="Permalink to &quot;relay_log_space_limit：防止中继日志写满磁盘，这里设置中继日志最大限额。但此设置存在主库崩溃，从库中继日志不全的情况，不到万不得已，不推荐使用。设置为0表示不启用该功能。该参数的默认值就是0。&quot;">​</a></h4><h4 id="sync-relay-log-这个参数和sync-binlog是一样的-它觉得了什么时候把从主节点同步过来的relaylog的内容刷新到磁盘中。" tabindex="-1">sync_relay_log：这个参数和sync_binlog是一样的，它觉得了什么时候把从主节点同步过来的relaylog的内容刷新到磁盘中。 <a class="header-anchor" href="#sync-relay-log-这个参数和sync-binlog是一样的-它觉得了什么时候把从主节点同步过来的relaylog的内容刷新到磁盘中。" aria-label="Permalink to &quot;sync_relay_log：这个参数和sync_binlog是一样的，它觉得了什么时候把从主节点同步过来的relaylog的内容刷新到磁盘中。&quot;">​</a></h4><p>如果sync_relay_log = 0，从主节点同步过来的relaylog日志内容并不会马上被刷新到磁盘中，而是由操作系统自己决定什么时候将同步过来的内容刷新到磁盘。</p><p>如果sync_relay_log = N &gt; 0，此时MySQL会在每间隔N个事件后，将relaylog的内容同步刷新到磁盘。此时有可能会导致丢失事务内容。</p><p>建议是设置为1，slave的I/O线程每次接收到master发送过来的binlog日志都要写入系统缓冲区，然后刷入relay log中继日志里，这样是最安全的，因为在崩溃的时候，你最多会丢失一个事务，但会造成磁盘的大量I/O。</p><p>详细请参考：<a href="https://dev.mysql.com/doc/refman/5.7/en/replication-options-replica.html#sysvar_sync_relay_log" target="_blank" rel="noreferrer">https://dev.mysql.com/doc/refman/5.7/en/replication-options-replica.html#sysvar_sync_relay_log</a></p><h4 id="sync-relay-log-info" tabindex="-1">sync_relay_log_info： <a class="header-anchor" href="#sync-relay-log-info" aria-label="Permalink to &quot;sync_relay_log_info：&quot;">​</a></h4><p>在sync_relay_log_info = 0的情况下：</p><p>如果relay_log_info_repository=FILE, 表示relaylog日志偏移量记录在日志文件relay-log.info中，由操作系统自己决定什么时候把relaylog日志的偏移量刷新到 relay-log.info 文件中。 如果 relay_log_info_repository=TABLE，表示relaylog日志偏移量记录在表mysql.slave_relay_log_info里面，如果这个表支持事务，例如是innodb存储引擎的表，那么表mysql.slave_relay_log_info中的数据内容会在每一个事务结束之后都会被更新。 如果 relay_log_info_repository=TABLE，表示relaylog日志偏移量记录在表mysql.slave_relay_log_info里面，如果这个表不支持事务，例如是myisam存储引擎的表，那么表mysql.slave_relay_log_info里面的信息永远不会被更新。 在sync_relay_log_info = N &gt; 0的情况下：</p><p>如果relay_log_info_repository=FILE, 表示relaylog日志偏移量记录在日志文件relay-log.info中，会每隔N个事务把relaylog日志的偏移量刷新到 relay-log.info 文件中。 如果 relay_log_info_repository=TABLE，表示relaylog日志偏移量记录在表mysql.slave_relay_log_info里面，如果这个表支持事务，例如是innodb存储引擎的表，那么表mysql.slave_relay_log_info中的数据内容会在每一个事务结束之后都会被更新。 如果 relay_log_info_repository=TABLE，表示relaylog日志偏移量记录在表mysql.slave_relay_log_info里面，如果这个表不支持事务，例如是myisam存储引擎的表，那么表mysql.slave_relay_log_info里面的信息会每间N个事件更新一次。 推荐使用relay_log_info_repository=TABLE，并且表mysql.slave_relay_log_info为innodb引擎表，这样的配置。这样的配置此时参数sync_relay_log_info的配置就不起作用了。</p><p>详细请参考：<a href="https://dev.mysql.com/doc/refman/5.7/en/replication-options-replica.html#sysvar_sync_relay_log_info" target="_blank" rel="noreferrer">https://dev.mysql.com/doc/refman/5.7/en/replication-options-replica.html#sysvar_sync_relay_log_info</a></p><h2 id="_4-relay-log日志的清除" tabindex="-1">4.relay log日志的清除 <a class="header-anchor" href="#_4-relay-log日志的清除" aria-label="Permalink to &quot;4.relay log日志的清除&quot;">​</a></h2><p>relaylog的删除，一般情况下不需要我们手动的去做。因为在MySQL的slave从节点上，当SQL集成读取完对应的relaylog日志之后，这个relaylog就被删除了，不需要我们手动去删除。</p><p>当我们执行reset slave或者reset slave all命令的时候，它就会重新生成一个新的relaylog日志文件，文件名称按照序号有序的递增。</p>`,45),p=[r];function o(i,y,c,g,t,b){return l(),s("div",null,p)}const d=a(e,[["render",o]]);export{_ as __pageData,d as default};
